// W12A: Process Outlook Status
// Classifies each tracker: cancelled | timechange | lastsynced
// Does NOT send emails. Does NOT touch reminder sent flags. Does NOT delete SF records.
// Only cancelled/missing Outlook events block reminders (Meeting_Status__c = Cancelled).
// RSVP status (declined/tentative/none/not found) does NOT block reminders — lastsynced only.
// Review_Notes__c only written on meaningful issues, not on clean accepted syncs.

const INTERNAL_EMAILS = ['user@example.com', 'colleague@example.com'];
const TIME_TOLERANCE_SEC = $('Meeting Status Sync Config').item.json.timeDiffToleranceSec || 60;

const trackerItems = $('Query Scheduled Trackers').all();
const outlookItems = $input.all();

function buildNote(existing, message) {
  const now = new Date();
  const pad = n => String(n).padStart(2, '0');
  const ts = now.getUTCFullYear() + '-' + pad(now.getUTCMonth()+1) + '-' + pad(now.getUTCDate())
    + ' ' + pad(now.getUTCHours()) + ':' + pad(now.getUTCMinutes()) + ' UTC';
  const tag = '[W12A ' + ts + '] ' + message;
  if (!existing || existing.trim() === '') return tag;
  return tag + '\n' + existing.trim();
}

function checkTimeChange(sfStartISO, sfEndISO, liveEvent) {
  let timeChanged = false;
  let newStartISO = '', newEndISO = '', new24hISO = '', new1hISO = '';
  if (sfStartISO && liveEvent.start?.dateTime) {
    const sfMs = new Date(sfStartISO).getTime();
    const outlookMs = new Date(liveEvent.start.dateTime).getTime();
    if (Math.abs(sfMs - outlookMs) / 1000 > TIME_TOLERANCE_SEC) {
      timeChanged = true;
      newStartISO = new Date(liveEvent.start.dateTime).toISOString();
      newEndISO = liveEvent.end?.dateTime ? new Date(liveEvent.end.dateTime).toISOString() : sfEndISO;
      new24hISO = new Date(new Date(liveEvent.start.dateTime).getTime() - 24 * 60 * 60 * 1000).toISOString();
      new1hISO = new Date(new Date(liveEvent.start.dateTime).getTime() - 1 * 60 * 60 * 1000).toISOString();
    }
  }
  return { timeChanged, newStartISO, newEndISO, new24hISO, new1hISO };
}

const results = [];

for (let i = 0; i < trackerItems.length; i++) {
  const tracker = trackerItems[i].json;
  const trackerId = String(tracker.Id || '');
  const iCalUID = String(tracker.Outlook_Event_ID__c || '').trim();
  const leadEmail = String(tracker.Lead_Email__c || '').trim().toLowerCase();
  const sfStartISO = String(tracker.Meeting_Start_Date_Time__c || '');
  const sfEndISO = String(tracker.Meeting_End_Date_Time__c || '');
  const existingNote = String(tracker.Review_Notes__c || '');

  if (!trackerId || !iCalUID || !leadEmail) continue;

  const matchingEvents = outlookItems.filter(item =>
    String(item.json.iCalUId || '').trim() === iCalUID
  );

  if (matchingEvents.length === 0) {
    results.push({ json: { trackerId, outcome: 'cancelled',
      newNote: buildNote(existingNote, 'Outlook event missing or deleted. Status set to Cancelled.'),
      iCalUID, leadEmail }});
    continue;
  }

  if (matchingEvents.length > 1) {
    results.push({ json: { trackerId, outcome: 'lastsynced', writeNote: true,
      newNote: buildNote(existingNote, matchingEvents.length + ' Outlook events matched iCalUID — ambiguous. Manual review needed.'),
      iCalUID, leadEmail }});
    continue;
  }

  const liveEvent = matchingEvents[0].json;

  if (liveEvent.isCancelled === true) {
    results.push({ json: { trackerId, outcome: 'cancelled',
      newNote: buildNote(existingNote, 'Outlook event is cancelled (isCancelled=true). Status set to Cancelled.'),
      iCalUID, leadEmail }});
    continue;
  }

  // Time change check — runs regardless of RSVP status
  const { timeChanged, newStartISO, newEndISO, new24hISO, new1hISO } = checkTimeChange(sfStartISO, sfEndISO, liveEvent);

  if (timeChanged) {
    results.push({ json: { trackerId, outcome: 'timechange',
      newStartISO, newEndISO, new24hISO, new1hISO,
      newNote: buildNote(existingNote, 'Meeting time changed in Outlook. SF start was ' + sfStartISO + ', Outlook start is ' + newStartISO + '. Tracker time and reminder times synced. Status kept Scheduled.'),
      iCalUID, leadEmail }});
    continue;
  }

  const attendees = Array.isArray(liveEvent.attendees) ? liveEvent.attendees : [];
  const leadAttendee = attendees.find(a => {
    const addr = String(a.emailAddress?.address || '').trim().toLowerCase();
    return addr === leadEmail && !INTERNAL_EMAILS.includes(addr);
  });

  if (!leadAttendee) {
    results.push({ json: { trackerId, outcome: 'lastsynced', writeNote: true,
      newNote: buildNote(existingNote, 'Lead not found in Outlook attendee list; reminders allowed per current policy.'),
      iCalUID, leadEmail }});
    continue;
  }

  const rsvp = String(leadAttendee.status?.response || '').trim().toLowerCase();

  if (rsvp === 'declined') {
    results.push({ json: { trackerId, outcome: 'lastsynced', writeNote: true,
      newNote: buildNote(existingNote, 'Lead RSVP is declined; reminders allowed per current policy.'),
      iCalUID, leadEmail }});
    continue;
  }

  if (rsvp !== 'accepted') {
    results.push({ json: { trackerId, outcome: 'lastsynced', writeNote: true,
      newNote: buildNote(existingNote, 'Lead RSVP is not accepted yet; reminders allowed per current policy.'),
      iCalUID, leadEmail }});
    continue;
  }

  // Clean: accepted, active, times match — Last_Synced__c only, do not touch Review_Notes__c
  results.push({ json: { trackerId, outcome: 'lastsynced', writeNote: false, iCalUID, leadEmail }});
}

return results.length > 0 ? results : [];

const results = [];
for (const item of $input.all()) {
  const d = item.json;
  if (d.writeNote === true) {
    results.push({ json: { trackerId: d.trackerId, newNote: d.newNote, writeNote: true } });
  } else {
    results.push({ json: { trackerId: d.trackerId, writeNote: false } });
  }
}
return results;
